 Queues (Built-In)

// Enqueue a task
await kv.enqueue({
 type: "send_email",
 to: "user@example.com",
 subject: "Welcome!",
});

// Process queue
kv.listenQueue(async (message) => {
 if (message.type === "send_email") {
 await sendEmail(message.to, message.subject);
 }
});

